// Analyze data quality and flag issues
const stats = $input.first().json;
const issues = [];

// Thresholds
const STALE_HOURS_THRESHOLD = 2;
const NULL_SENTIMENT_PCT_THRESHOLD = 10;
const MIN_DAILY_PRICES = 10;
const MIN_DAILY_NEWS = 5;

// Check for stale price data
if (stats.hours_since_last_price > STALE_HOURS_THRESHOLD) {
  issues.push(`⚠️ Price data is stale: ${stats.hours_since_last_price.toFixed(1)}h since last update`);
}

// Check for stale news data
if (stats.hours_since_last_news > STALE_HOURS_THRESHOLD) {
  issues.push(`⚠️ News data is stale: ${stats.hours_since_last_news.toFixed(1)}h since last update`);
}

// Check null sentiment rate
if (stats.null_sentiment_pct > NULL_SENTIMENT_PCT_THRESHOLD) {
  issues.push(`⚠️ High null sentiment rate: ${stats.null_sentiment_pct}% (${stats.null_sentiment_count} articles)`);
}

// Check minimum data volume
if (stats.total_prices < MIN_DAILY_PRICES) {
  issues.push(`⚠️ Low price volume: only ${stats.total_prices} records in 24h`);
}

if (stats.total_news < MIN_DAILY_NEWS) {
  issues.push(`⚠️ Low news volume: only ${stats.total_news} articles in 24h`);
}

// Build report
const hasIssues = issues.length > 0;
const report = [
  `📊 **Daily Data Quality Report**`,
  ``,
  `**Timestamp:** ${new Date().toISOString()}`,
  ``,
  `**Price Data (24h):**`,
  `- Total records: ${stats.total_prices}`,
  `- Unique symbols: ${stats.unique_symbols}`,
  `- Hours since last: ${(stats.hours_since_last_price || 0).toFixed(1)}`,
  ``,
  `**News Data (24h):**`,
  `- Total articles: ${stats.total_news}`,
  `- Null sentiment: ${stats.null_sentiment_count} (${stats.null_sentiment_pct || 0}%)`,
  `- Hours since last: ${(stats.hours_since_last_news || 0).toFixed(1)}`,
].join('\n');

const issueReport = hasIssues 
  ? `\n\n**Issues Found:**\n${issues.join('\n')}`
  : `\n\n✅ **All checks passed!**`;

return [{
  json: {
    has_issues: hasIssues,
    issue_count: issues.length,
    issues: issues,
    report: report + issueReport,
    stats: stats
  }
}];

// Log issues locally
console.log('DATA QUALITY ISSUES DETECTED:');
console.log($json.report);
return [{ json: { status: 'logged', ...$json } }];

// All checks passed - log success
console.log('Daily quality check passed:', $json.report);
return [{ json: { status: 'all_checks_passed', ...$json } }];
